diff --git a/src/session/flows/refresh-flow.ts b/src/session/flows/refresh-flow.ts
index 3f88df7..9c7d510 100644
--- a/src/session/flows/refresh-flow.ts
+++ b/src/session/flows/refresh-flow.ts
@@ -1 +1,6 @@
-export function refresh(token: string) { return { token, familyId: 'family-1' }; }
+const used = new Set<string>();
+export function refresh(token: string) {
+  if (used.has(token)) throw new Error('replay');
+  used.add(token);
+  return { token: token + '-rotated', familyId: 'family-1' };
+}
